import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../api";
import EventList from "../components/EventList";

const ParticipantDashboard = () => {
  const navigate = useNavigate();
  const [registeredEvents, setRegisteredEvents] = useState([]);
  const [recommendedEvents, setRecommendedEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        const registeredRes = await API.get("/events/my-registrations");
        const recommendedRes = await API.get("/events");

        setRegisteredEvents(registeredRes.data);
        setRecommendedEvents(recommendedRes.data);
      } catch (err) {
        console.error(err);
        setError("Failed to load dashboard data");
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, []);

  const handleEventClick = (event) => {
    navigate(`/events/${event._id}`);
  };

  return (
    <div style={styles.container}>
      <h2>Welcome, {user?.name || "Participant"}</h2>

      {loading && <p>Loading dashboard...</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {!loading && !error && (
        <>
          <section style={styles.section}>
            <h3>Your Registered Events</h3>
            {registeredEvents.length === 0 ? (
              <p>You haven't registered for any events yet.</p>
            ) : (
              <EventList
                events={registeredEvents}
                onEventClick={handleEventClick}
              />
            )}
          </section>

          <section style={styles.section}>
            <h3>Explore Events</h3>
            <EventList
              events={recommendedEvents}
              onEventClick={handleEventClick}
            />
          </section>
        </>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: "1000px",
    margin: "40px auto",
    padding: "20px",
  },
  section: {
    marginTop: "30px",
  },
};

export default ParticipantDashboard;
